function genId() { return Math.random().toString(36).substr(2,9); }
const medal = (i) => ["🥇","🥈","🥉"][i] ?? `${i+1}.`;
const cls = (id) => ALL_CLASSES.find(c=>c.id===id);

function rankEntries(classId, entries, scores) {
  const c = cls(classId);
  const ces = entries.filter(e=>e.classId===classId && scores[e.id]);
  if (!c) return ces;
  if (c.scoringType==="faults") return [...ces].sort((a,b)=>scores[a.id].faults!==scores[b.id].faults?scores[a.id].faults-scores[b.id].faults:scores[a.id].time-scores[b.id].time);
  if (c.scoringType==="topscore") return [...ces].sort((a,b)=>(scores[b.id].points||0)-(scores[a.id].points||0));
  return [...ces].sort((a,b)=>(scores[b.id].heightCleared||0)-(scores[a.id].heightCleared||0));
}

function canAddClass(newCls, existingEntries, ownerId, excludeId, day, horseName) {
  const dayIds = ALL_CLASSES.filter(c=>c.day===day).map(c=>c.id);
  const mine = existingEntries.filter(e=>e.ownerId===ownerId && dayIds.includes(e.classId) && e.id!==excludeId && (horseName?e.horse?.trim().toLowerCase()===horseName.trim().toLowerCase():true));
  if (!newCls.comp) {
    if (mine.filter(e=>!cls(e.classId)?.comp).length >= 2) return "Each horse can only enter 2 non-competitive classes per day.";
  } else {
    if (day==="sat") {
      if (!newCls.special && mine.filter(e=>cls(e.classId)?.comp&&!cls(e.classId)?.special).length >= 1) return "Each horse can only enter 1 competitive height class on Saturday.";
      if (mine.find(e=>e.classId===newCls.id)) return "This horse is already entered in this class.";
    } else {
      if (mine.filter(e=>cls(e.classId)?.comp).length >= 1) return "Each horse can only enter 1 competitive class on Sunday.";
    }
  }
  return null;
}

// ── SCHEDULE CALCULATOR ───────────────────────────────────────────────────────
function calcSchedule(day, entries, classStartTimes) {
  const heights = HEIGHTS_FOR_DAY[day] || SAT_HEIGHTS;
  const dayClasses = [];
  heights.forEach(name => {
    [false, true].forEach(isComp => {
      const c = ALL_CLASSES.find(x=>x.day===day&&x.name===name&&x.comp===isComp);
      if (c && entries.filter(e=>e.classId===c.id).length > 0) dayClasses.push(c);
    });
  });

  const startStr = SHOW_START[day] || "07:30";
  const [sh, sm] = startStr.split(":").map(Number);
  let currentMins = sh * 60 + sm;
  const schedule = [];

  dayClasses.forEach((c, idx) => {
    const count = entries.filter(e=>e.classId===c.id).length;
    // If organiser has set actual start time, use that
    const actualStart = classStartTimes[c.id];
    if (actualStart) {
      const [ah, am] = actualStart.split(":").map(Number);
      currentMins = ah * 60 + am;
    }
    const estMins = currentMins;
    const duration = count * MINS_PER_HORSE + (idx > 0 ? MINS_COURSE_CHANGE : 0);
    schedule.push({ cls: c, count, estMins, actualStart, duration });
    currentMins += duration;
  });
  return schedule;
}

function minsToTime(mins) {
  const h = Math.floor(mins / 60) % 24;
  const m = mins % 60;
  return `${String(h).padStart(2,"0")}:${String(m).padStart(2,"0")}`;
}

// ── STYLES ────────────────────────────────────────────────────────────────────
// ── CAMPING / YARD CAPACITY ──────────────────────────────────────────────────
// Each booking (truck/float OR horse yard) occupies `quantity` of the 40 total yards, per night
function yardsUsedOnNight(bookings, date) {
  return bookings.filter(b => b.nights.includes(date)).reduce((sum,b)=>sum+(b.quantity||1),0);
}
function yardsAvailableOnNight(bookings, date) {
  return TOTAL_YARDS - yardsUsedOnNight(bookings, date);
}
function nightsAreFullyAvailable(bookings, nights, quantity=1, excludeBookingId) {
  const relevant = excludeBookingId ? bookings.filter(b => b.id !== excludeBookingId) : bookings;
  return nights.filter(date => (TOTAL_YARDS - yardsUsedOnNight(relevant, date)) < quantity);
}

