  const bg={error:"#7f1d1d",info:"#1e3a5f",success:"#14532d"}[toast.type]||"#14532d";
  return <div style={{position:"fixed",top:20,right:20,zIndex:9999,background:bg,color:"#fff",padding:"11px 22px",borderRadius:8,boxShadow:"0 4px 24px rgba(0,0,0,0.4)",fontFamily:"Georgia,serif",fontSize:14,border:"1px solid rgba(255,255,255,0.1)"}}>{toast.msg}</div>;
